  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 83 ORDER BY created_at DESC LIMIT 1), 'reading', 9, '다음 글의 내용과 같은 것을 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-83/reading/q9.png', NULL, NULL, '["이 행사는 한 달 동안 진행된다.","사진은 이메일로 제출해야 한다.","인주시에서 올해 찍은 사진을 내면 된다.","이 행사에 참여하면 인주시의 옛날 사진을 받는다."]'::jsonb, 2, '이 행사는 한 달 동안 진행된다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 83 ORDER BY created_at DESC LIMIT 1), 'reading', 10, '다음 글 또는 그래프의 내용과 같은 것을 고르십시오.', 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-83/reading/q10.png', NULL, NULL, '["용돈 중 물건 구입비의 비율이 가장 낮았다.","학원비 사용은 교통비보다 두 배 이상 많았다.","대학생들은 용돈의 절반 이상을 식비로 지출했다.","대학생들은 문화생활비보다 교통비를 더 적게 사용했다."]'::jsonb, 2, '대학생들은 용돈의 절반 이상을 식비로 지출했다.', NULL),
